'use client';

import { useState, useEffect, useRef } from 'react';
import styles from './page.module.css';

const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';

const VIEW_HOME = 'home';
const VIEW_SESSION = 'session';
const VIEW_AREA = 'area';

// Default session name — today's date formatted nicely
const getDefaultSessionName = () => {
  return `Inventory - ${new Date().toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  })}`;
};

// Suggested area names for restaurants
const AREA_SUGGESTIONS = [
  'Bar',
  'Dry Storage',
  'Walk-In',
  'Produce',
  'Freezer',
  'Prep Kitchen',
  'Front of House',
  'Cellar',
];

export default function Home() {

  // ─── Navigation state ───────────────────────────────────────────────────────
  const [view, setView] = useState(VIEW_HOME);
  const [currentSession, setCurrentSession] = useState(null);
  const [currentArea, setCurrentArea] = useState(null);

  // ─── Home screen state ──────────────────────────────────────────────────────
  const [businessId, setBusinessId] = useState('demo-business');
  const [sessions, setSessions] = useState([]);
  const [loadingSessions, setLoadingSessions] = useState(false);
  const [newSessionName, setNewSessionName] = useState('');
  const [showNewSessionInput, setShowNewSessionInput] = useState(false);
  const [creatingSession, setCreatingSession] = useState(false);

  // ─── Session screen state ───────────────────────────────────────────────────
  const [areas, setAreas] = useState([]);
  const [loadingAreas, setLoadingAreas] = useState(false);
  const [newAreaName, setNewAreaName] = useState('');
  const [showNewAreaInput, setShowNewAreaInput] = useState(false);
  const [creatingArea, setCreatingArea] = useState(false);

  // ─── Area / extraction state ─────────────────────────────────────────────────
  const [selectedFile, setSelectedFile] = useState(null);
  const [fileName, setFileName] = useState('');
  const [uploading, setUploading] = useState(false);
  const [uploadStatus, setUploadStatus] = useState('');
  const [uploadedFilePath, setUploadedFilePath] = useState('');
  const [ocrText, setOcrText] = useState('');
  const [runningOCR, setRunningOCR] = useState(false);
  const [inventory, setInventory] = useState([]);
  const [parsingInventory, setParsingInventory] = useState(false);
  const [imagePreview, setImagePreview] = useState(null);

  // ─── Template state ──────────────────────────────────────────────────────────
  const [templateFile, setTemplateFile] = useState(null);
  const [templateFileName, setTemplateFileName] = useState('');
  const [uploadingTemplate, setUploadingTemplate] = useState(false);
  const [currentTemplate, setCurrentTemplate] = useState(null);

  const cameraInputRef = useRef(null);
  const galleryInputRef = useRef(null);

  useEffect(() => {
    if (view === VIEW_HOME) loadSessions();
  }, [businessId, view]);

  useEffect(() => {
    loadCurrentTemplate();
  }, [businessId]);

  useEffect(() => {
    if (view === VIEW_SESSION && currentSession) loadAreas(currentSession.id);
  }, [view, currentSession]);

  useEffect(() => {
    if (view === VIEW_AREA) {
      setSelectedFile(null);
      setFileName('');
      setImagePreview(null);
      setOcrText('');
      setUploadStatus('');
      setUploadedFilePath('');
      setInventory([]);
    }
  }, [currentArea]);

  // ═══════════════════════════════════════════════════════════════════════════════
  // SESSION HANDLERS
  // ═══════════════════════════════════════════════════════════════════════════════

  const loadSessions = async () => {
    setLoadingSessions(true);
    try {
      const res = await fetch(`${API_BASE}/api/sessions/${businessId}`);
      const data = await res.json();
      if (data.success) setSessions(data.sessions);
    } catch (err) {
      console.error('Failed to load sessions:', err);
    } finally {
      setLoadingSessions(false);
    }
  };

  const handleOpenNewSessionInput = () => {
    setNewSessionName(getDefaultSessionName());
    setShowNewSessionInput(true);
  };

  const handleCreateSession = async () => {
    if (!newSessionName.trim()) return;
    setCreatingSession(true);
    try {
      const res = await fetch(`${API_BASE}/api/sessions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newSessionName.trim(), businessId }),
      });
      const data = await res.json();
      if (data.success) {
        setNewSessionName('');
        setShowNewSessionInput(false);
        setCurrentSession(data.session);
        setView(VIEW_SESSION);
      }
    } catch (err) {
      console.error('Failed to create session:', err);
    } finally {
      setCreatingSession(false);
    }
  };

  const handleDeleteSession = async (sessionId) => {
    if (!confirm('Delete this session and all its data?')) return;
    try {
      const res = await fetch(`${API_BASE}/api/sessions/${sessionId}`, { method: 'DELETE' });
      const data = await res.json();
      if (data.success) setSessions((prev) => prev.filter((s) => s.id !== sessionId));
    } catch (err) {
      console.error('Failed to delete session:', err);
    }
  };

  const handleContinueSession = (session) => {
    setCurrentSession(session);
    setView(VIEW_SESSION);
  };

  // ═══════════════════════════════════════════════════════════════════════════════
  // AREA HANDLERS
  // ═══════════════════════════════════════════════════════════════════════════════

  const loadAreas = async (sessionId) => {
    setLoadingAreas(true);
    try {
      const res = await fetch(`${API_BASE}/api/sessions/${sessionId}/areas`);
      const data = await res.json();
      if (data.success) setAreas(data.areas);
    } catch (err) {
      console.error('Failed to load areas:', err);
    } finally {
      setLoadingAreas(false);
    }
  };

  const handleCreateArea = async () => {
    if (!newAreaName.trim()) return;
    setCreatingArea(true);
    try {
      const res = await fetch(`${API_BASE}/api/sessions/${currentSession.id}/areas`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newAreaName.trim(), position: areas.length }),
      });
      const data = await res.json();
      if (data.success) {
        setNewAreaName('');
        setShowNewAreaInput(false);
        setAreas((prev) => [...prev, data.area]);
      }
    } catch (err) {
      console.error('Failed to create area:', err);
    } finally {
      setCreatingArea(false);
    }
  };

  const handleDeleteArea = async (areaId) => {
    if (!confirm('Delete this area and all its items?')) return;
    try {
      const res = await fetch(`${API_BASE}/api/areas/${areaId}`, { method: 'DELETE' });
      const data = await res.json();
      if (data.success) setAreas((prev) => prev.filter((a) => a.id !== areaId));
    } catch (err) {
      console.error('Failed to delete area:', err);
    }
  };

  const handleEnterArea = (area) => {
    setCurrentArea(area);
    setView(VIEW_AREA);
  };

  // ═══════════════════════════════════════════════════════════════════════════════
  // TEMPLATE HANDLERS
  // ═══════════════════════════════════════════════════════════════════════════════

  const loadCurrentTemplate = async () => {
    try {
      const res = await fetch(`${API_BASE}/api/templates/${businessId}`);
      const data = await res.json();
      if (data.success) setCurrentTemplate(data.template);
      else setCurrentTemplate(null);
    } catch (err) {
      setCurrentTemplate(null);
    }
  };

  const handleTemplateSelect = (event) => {
    const file = event.target.files[0];
    if (file) {
      const ext = file.name.toLowerCase();
      if (ext.endsWith('.xlsx') || ext.endsWith('.xls') || ext.endsWith('.csv')) {
        setTemplateFile(file);
        setTemplateFileName(file.name);
      } else {
        alert('Please select a .xlsx or .csv file');
      }
    }
  };

  const handleTemplateUpload = async () => {
    if (!templateFile) return;
    setUploadingTemplate(true);
    try {
      const formData = new FormData();
      formData.append('template', templateFile);
      formData.append('businessId', businessId);
      const res = await fetch(`${API_BASE}/api/templates/upload`, { method: 'POST', body: formData });
      const data = await res.json();
      if (data.success) {
        alert(`Template uploaded!\nColumns: ${data.columns.join(', ')}`);
        setCurrentTemplate({ id: data.templateId, columns: data.columns, business_id: businessId });
        setTemplateFile(null);
        setTemplateFileName('');
      } else {
        alert(`Template upload failed: ${data.error}`);
      }
    } catch (err) {
      alert(`Template upload error: ${err.message}`);
    } finally {
      setUploadingTemplate(false);
    }
  };

  // ═══════════════════════════════════════════════════════════════════════════════
  // EXTRACTION HANDLERS
  // ═══════════════════════════════════════════════════════════════════════════════

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    if (file) {
      setSelectedFile(file);
      setFileName(file.name);
      setUploadStatus('');
      setOcrText('');
      setInventory([]);
      const reader = new FileReader();
      reader.onload = (ev) => setImagePreview(ev.target.result);
      reader.readAsDataURL(file);
    }
  };

  const handleUploadClick = async () => {
    if (!selectedFile) { alert('Please select an image file first'); return; }
    setParsingInventory(true);
    try {
      const formData = new FormData();
      formData.append('image', selectedFile);
      formData.append('businessId', businessId);
      formData.append('areaId', currentArea.id);
      formData.append('sessionId', currentSession.id);
      const res = await fetch(`${API_BASE}/api/parse-inventory`, { method: 'POST', body: formData });
      const data = await res.json();
      if (data.success) setInventory((prev) => [...prev, ...data.inventory]);
    } catch (err) {
      console.error('Upload error:', err);
    } finally {
      setParsingInventory(false);
    }
  };

  const handleOCRClick = async () => {
    if (!uploadedFilePath) { alert('Please upload an image first'); return; }
    setRunningOCR(true);
    setOcrText('Running OCR...');
    try {
      const res = await fetch(`${API_BASE}/api/ocr`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ imagePath: uploadedFilePath }),
      });
      const data = await res.json();
      if (data.success) setOcrText(data.text || 'No text detected');
      else setOcrText(`Error: ${data.error}`);
    } catch (err) {
      setOcrText(`Error: ${err.message}`);
    } finally {
      setRunningOCR(false);
    }
  };

  const handleParseInventory = async () => {
    if (!selectedFile) { alert('Please select an image file first'); return; }
    setParsingInventory(true);
    try {
      const formData = new FormData();
      formData.append('image', selectedFile);
      formData.append('businessId', businessId);
      formData.append('areaId', currentArea.id);
      formData.append('sessionId', currentSession.id);
      const res = await fetch(`${API_BASE}/api/parse-inventory`, { method: 'POST', body: formData });
      const data = await res.json();
      if (data.success) setInventory((prev) => [...prev, ...data.inventory]);
      else alert(`Parse failed: ${data.error}`);
    } catch (err) {
      alert(`Parse error: ${err.message}`);
    } finally {
      setParsingInventory(false);
    }
  };

  const handleExportArea = async () => {
    if (inventory.length === 0) { alert('No inventory to export'); return; }
    try {
      const res = await fetch(`${API_BASE}/api/export`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ inventory, businessId, templateId: currentTemplate?.id, areaName: currentArea.name }),
      });
      if (res.ok) {
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${currentArea.name}-inventory.xlsx`;
        document.body.appendChild(a);
        a.click();
        window.URL.revokeObjectURL(url);
        document.body.removeChild(a);
      } else {
        alert('Export failed');
      }
    } catch (err) {
      alert(`Export error: ${err.message}`);
    }
  };

  const handleExportSession = async () => {
    try {
      const res = await fetch(`${API_BASE}/api/sessions/${currentSession.id}/export`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ businessId, templateId: currentTemplate?.id }),
      });
      if (res.ok) {
        const blob = await res.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${currentSession.name}-full-inventory.xlsx`;
        document.body.appendChild(a);
        a.click();
        window.URL.revokeObjectURL(url);
        document.body.removeChild(a);
      } else {
        alert('Session export failed');
      }
    } catch (err) {
      alert(`Export error: ${err.message}`);
    }
  };

  const getColumns = () => {
    if (currentTemplate && currentTemplate.columns) return currentTemplate.columns;
    if (inventory.length > 0) return Object.keys(inventory[0]);
    return ['Item', 'Category', 'Quantity', 'Unit Price', 'Total Value', 'Condition'];
  };

  // ═══════════════════════════════════════════════════════════════════════════════
  // SHARED STYLES
  // ═══════════════════════════════════════════════════════════════════════════════

  const cardStyle = {
    background: '#fff',
    border: '1px solid #e5e7eb',
    borderRadius: '14px',
    padding: '16px',
    marginBottom: '14px',
  };

  const backButtonStyle = {
    background: 'none',
    border: 'none',
    color: '#4f46e5',
    fontWeight: 600,
    fontSize: '0.95rem',
    cursor: 'pointer',
    padding: '8px 0',
    marginBottom: '12px',
    display: 'flex',
    alignItems: 'center',
    gap: '6px',
  };

  const primaryButtonStyle = {
    background: '#4f46e5',
    color: '#fff',
    border: 'none',
    borderRadius: '10px',
    padding: '12px 20px',
    fontWeight: 700,
    fontSize: '0.95rem',
    cursor: 'pointer',
    width: '100%',
    marginTop: '8px',
  };

  const dangerButtonStyle = {
    background: 'none',
    border: '1px solid #fca5a5',
    color: '#dc2626',
    borderRadius: '8px',
    padding: '6px 12px',
    fontSize: '0.85rem',
    cursor: 'pointer',
    fontWeight: 600,
  };

  const inputStyle = {
    width: '100%',
    border: '1px solid #d1d5db',
    borderRadius: '8px',
    padding: '10px 12px',
    fontSize: '0.95rem',
    boxSizing: 'border-box',
    marginBottom: '8px',
  };

  const stickyBarStyle = {
    position: 'fixed',
    bottom: 0,
    left: 0,
    right: 0,
    zIndex: 100,
    background: '#fff',
    borderTop: '2px solid #e5e7eb',
    boxShadow: '0 -4px 16px rgba(0,0,0,0.08)',
    padding: '12px 16px',
  };

  // ═══════════════════════════════════════════════════════════════════════════════
  // RENDER: HOME
  // ═══════════════════════════════════════════════════════════════════════════════

  if (view === VIEW_HOME) {
    return (
      <div className={styles.container}>
        <main className={styles.main} style={{ paddingBottom: '40px' }}>
          <h1 className={styles.title}>Inventory Tool</h1>

          {/* Business ID */}
          <div style={cardStyle}>
            <label style={{ fontWeight: 600, fontSize: '0.9rem', color: '#374151' }}>Business ID</label>
            <input
              type="text"
              value={businessId}
              onChange={(e) => setBusinessId(e.target.value)}
              style={{ ...inputStyle, marginTop: '6px' }}
              placeholder="Enter your business ID"
            />
          </div>

          {/* Sessions list */}
          <div style={cardStyle}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '14px' }}>
              <h2 style={{ margin: 0, fontSize: '1.1rem' }}>Inventory Sessions</h2>
              <button
                onClick={handleOpenNewSessionInput}
                style={{
                  background: '#4f46e5', color: '#fff', border: 'none',
                  borderRadius: '8px', padding: '8px 14px',
                  fontWeight: 700, cursor: 'pointer', fontSize: '0.9rem',
                }}
              >
                + New Session
              </button>
            </div>

            {/* New session input — pre-filled with today's date */}
            {showNewSessionInput && (
              <div style={{ marginBottom: '14px', padding: '12px', background: '#f0f4ff', borderRadius: '10px' }}>
                <label style={{ fontSize: '0.82rem', color: '#6b7280', fontWeight: 600, marginBottom: '6px', display: 'block' }}>
                  Session name — edit or keep the default
                </label>
                <input
                  type="text"
                  value={newSessionName}
                  onChange={(e) => setNewSessionName(e.target.value)}
                  style={inputStyle}
                  onKeyDown={(e) => e.key === 'Enter' && handleCreateSession()}
                  autoFocus
                />
                <div style={{ display: 'flex', gap: '8px' }}>
                  <button
                    onClick={handleCreateSession}
                    disabled={creatingSession || !newSessionName.trim()}
                    style={{ ...primaryButtonStyle, width: 'auto', flex: 1, marginTop: 0 }}
                  >
                    {creatingSession ? 'Creating...' : 'Create Session'}
                  </button>
                  <button
                    onClick={() => { setShowNewSessionInput(false); setNewSessionName(''); }}
                    style={{ ...dangerButtonStyle, marginTop: 0 }}
                  >
                    Cancel
                  </button>
                </div>
              </div>
            )}

            {/* Session list */}
            {loadingSessions ? (
              <p style={{ color: '#9ca3af', textAlign: 'center' }}>Loading sessions...</p>
            ) : sessions.length === 0 ? (
              <p style={{ color: '#9ca3af', textAlign: 'center', padding: '20px 0' }}>
                No sessions yet. Create one to get started.
              </p>
            ) : (
              sessions.map((session) => (
                <div key={session.id} style={{
                  border: '1px solid #e5e7eb', borderRadius: '10px',
                  padding: '12px 14px', marginBottom: '10px',
                  display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                }}>
                  <div>
                    <p style={{ margin: 0, fontWeight: 700, fontSize: '0.95rem' }}>{session.name}</p>
                    <p style={{ margin: '2px 0 0', fontSize: '0.78rem', color: '#6b7280' }}>
                      {new Date(session.created_at).toLocaleDateString()} &middot;{' '}
                      <span style={{ color: session.status === 'completed' ? '#16a34a' : '#d97706', fontWeight: 600 }}>
                        {session.status === 'completed' ? 'Completed' : 'In Progress'}
                      </span>
                    </p>
                  </div>
                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button
                      onClick={() => handleContinueSession(session)}
                      style={{
                        background: '#4f46e5', color: '#fff', border: 'none',
                        borderRadius: '8px', padding: '7px 14px',
                        fontWeight: 700, cursor: 'pointer', fontSize: '0.85rem',
                      }}
                    >
                      {session.status === 'completed' ? 'View' : 'Continue'}
                    </button>
                    <button onClick={() => handleDeleteSession(session.id)} style={dangerButtonStyle}>
                      Delete
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>

          {/* Template management */}
          <details style={cardStyle}>
            <summary style={{ fontWeight: 700, cursor: 'pointer', fontSize: '1rem' }}>
              Template Management
            </summary>
            <div style={{ marginTop: '12px' }}>
              {currentTemplate ? (
                <p style={{ color: '#16a34a', fontWeight: 600, fontSize: '0.9rem' }}>
                  Template active: {currentTemplate.columns.join(', ')}
                </p>
              ) : (
                <p style={{ color: '#6b7280', fontSize: '0.9rem' }}>No template uploaded yet.</p>
              )}
              <input
                type="file"
                id="templateInput"
                accept=".xlsx,.xls,.csv"
                onChange={handleTemplateSelect}
                className={styles.fileInput}
                disabled={uploadingTemplate}
              />
              <label htmlFor="templateInput" className={styles.fileLabel}>
                {templateFileName || 'Choose template file (.xlsx or .csv)'}
              </label>
              {templateFile && (
                <button onClick={handleTemplateUpload} style={primaryButtonStyle} disabled={uploadingTemplate}>
                  {uploadingTemplate ? 'Uploading...' : 'Upload Template'}
                </button>
              )}
            </div>
          </details>

        </main>
      </div>
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════════
  // RENDER: SESSION
  // ═══════════════════════════════════════════════════════════════════════════════

  if (view === VIEW_SESSION) {
    return (
      <div className={styles.container}>

        <div style={stickyBarStyle}>
          <button
            onClick={handleExportSession}
            style={{
              width: '100%', background: '#16a34a', color: '#fff',
              fontWeight: 700, fontSize: '1rem', border: 'none',
              borderRadius: '12px', padding: '14px', cursor: 'pointer',
            }}
          >
            Export Full Session to Excel
          </button>
        </div>

        <main className={styles.main} style={{ paddingBottom: '90px' }}>

          <button style={backButtonStyle} onClick={() => { setView(VIEW_HOME); setCurrentSession(null); setAreas([]); }}>
            &larr; All Sessions
          </button>

          <h1 className={styles.title} style={{ fontSize: '1.5rem', marginBottom: '4px' }}>
            {currentSession.name}
          </h1>
          <p style={{ color: '#6b7280', fontSize: '0.85rem', marginTop: 0, marginBottom: '20px' }}>
            {new Date(currentSession.created_at).toLocaleDateString()}
          </p>

          <div style={cardStyle}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '14px' }}>
              <h2 style={{ margin: 0, fontSize: '1.1rem' }}>Areas</h2>
              <button
                onClick={() => setShowNewAreaInput((v) => !v)}
                style={{
                  background: '#4f46e5', color: '#fff', border: 'none',
                  borderRadius: '8px', padding: '8px 14px',
                  fontWeight: 700, cursor: 'pointer', fontSize: '0.9rem',
                }}
              >
                + Add Area
              </button>
            </div>

            {/* New area input with suggestions */}
            {showNewAreaInput && (
              <div style={{ marginBottom: '14px', padding: '12px', background: '#f0f4ff', borderRadius: '10px' }}>
                <label style={{ fontSize: '0.82rem', color: '#6b7280', fontWeight: 600, marginBottom: '6px', display: 'block' }}>
                  Type a name or tap a suggestion
                </label>

                {/* Suggestion chips */}
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', marginBottom: '10px' }}>
                  {AREA_SUGGESTIONS.filter(s => !areas.find(a => a.name.toLowerCase() === s.toLowerCase())).map((suggestion) => (
                    <button
                      key={suggestion}
                      onClick={() => setNewAreaName(suggestion)}
                      style={{
                        background: newAreaName === suggestion ? '#4f46e5' : '#e0e7ff',
                        color: newAreaName === suggestion ? '#fff' : '#3730a3',
                        border: 'none',
                        borderRadius: '20px',
                        padding: '6px 14px',
                        fontSize: '0.85rem',
                        fontWeight: 600,
                        cursor: 'pointer',
                      }}
                    >
                      {suggestion}
                    </button>
                  ))}
                </div>

                <input
                  type="text"
                  value={newAreaName}
                  onChange={(e) => setNewAreaName(e.target.value)}
                  placeholder="Or type a custom area name..."
                  style={inputStyle}
                  onKeyDown={(e) => e.key === 'Enter' && handleCreateArea()}
                />
                <div style={{ display: 'flex', gap: '8px' }}>
                  <button
                    onClick={handleCreateArea}
                    disabled={creatingArea || !newAreaName.trim()}
                    style={{ ...primaryButtonStyle, width: 'auto', flex: 1, marginTop: 0 }}
                  >
                    {creatingArea ? 'Adding...' : 'Add Area'}
                  </button>
                  <button
                    onClick={() => { setShowNewAreaInput(false); setNewAreaName(''); }}
                    style={{ ...dangerButtonStyle, marginTop: 0 }}
                  >
                    Cancel
                  </button>
                </div>
              </div>
            )}

            {loadingAreas ? (
              <p style={{ color: '#9ca3af', textAlign: 'center' }}>Loading areas...</p>
            ) : areas.length === 0 ? (
              <p style={{ color: '#9ca3af', textAlign: 'center', padding: '20px 0' }}>
                No areas yet. Add one to start capturing inventory.
              </p>
            ) : (
              areas.map((area) => (
                <div key={area.id} style={{
                  border: '1px solid #e5e7eb', borderRadius: '10px',
                  padding: '12px 14px', marginBottom: '10px',
                  display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                }}>
                  <p style={{ margin: 0, fontWeight: 700, fontSize: '0.95rem' }}>{area.name}</p>
                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button
                      onClick={() => handleEnterArea(area)}
                      style={{
                        background: '#4f46e5', color: '#fff', border: 'none',
                        borderRadius: '8px', padding: '7px 14px',
                        fontWeight: 700, cursor: 'pointer', fontSize: '0.85rem',
                      }}
                    >
                      Open
                    </button>
                    <button onClick={() => handleDeleteArea(area.id)} style={dangerButtonStyle}>
                      Delete
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>

        </main>
      </div>
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════════
  // RENDER: AREA
  // ═══════════════════════════════════════════════════════════════════════════════

  if (view === VIEW_AREA) {
    return (
      <div className={styles.container}>

        <div style={stickyBarStyle}>
          {inventory.length > 0 ? (
            <button
              onClick={handleExportArea}
              style={{
                width: '100%', background: '#16a34a', color: '#fff',
                fontWeight: 700, fontSize: '1rem', border: 'none',
                borderRadius: '12px', padding: '14px', cursor: 'pointer',
              }}
            >
              Export {currentArea.name} to Excel ({inventory.length} items)
            </button>
          ) : (
            <div style={{ textAlign: 'center', color: '#9ca3af', fontSize: '0.9rem', padding: '10px', fontWeight: 500 }}>
              Export will appear here after extraction
            </div>
          )}
        </div>

        <main className={styles.main} style={{ paddingBottom: '90px' }}>

          <button style={backButtonStyle} onClick={() => { setView(VIEW_SESSION); setCurrentArea(null); }}>
            &larr; {currentSession.name}
          </button>

          <h1 className={styles.title} style={{ fontSize: '1.5rem', marginBottom: '20px' }}>
            {currentArea.name}
          </h1>

          {/* Camera / Upload card */}
          <div style={{
            background: '#f0f4ff', border: '2px solid #c7d2fe',
            borderRadius: '16px', padding: '20px', marginBottom: '20px',
          }}>
            <h2 style={{ marginTop: 0, marginBottom: '16px', fontSize: '1.1rem' }}>Capture or Upload Image</h2>

            {imagePreview && (
              <div style={{ marginBottom: '14px', borderRadius: '10px', overflow: 'hidden', border: '1px solid #c7d2fe' }}>
                <img src={imagePreview} alt="Selected" style={{ width: '100%', maxHeight: '220px', objectFit: 'cover', display: 'block' }} />
                <p style={{ margin: 0, padding: '6px 10px', background: '#f8fafc', fontSize: '0.8rem', color: '#64748b' }}>{fileName}</p>
              </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', marginBottom: '14px' }}>
              <button
                onClick={() => cameraInputRef.current?.click()}
                style={{
                  background: '#4f46e5', color: '#fff', border: 'none', borderRadius: '12px',
                  padding: '18px 8px', fontSize: '0.95rem', fontWeight: 700, cursor: 'pointer',
                  display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px',
                }}
              >
                Take Photo
              </button>
              <input ref={cameraInputRef} type="file" accept="image/*" capture="environment" style={{ display: 'none' }} onChange={handleFileSelect} />

              <button
                onClick={() => galleryInputRef.current?.click()}
                style={{
                  background: '#e0e7ff', color: '#3730a3', border: 'none', borderRadius: '12px',
                  padding: '18px 8px', fontSize: '0.95rem', fontWeight: 700, cursor: 'pointer',
                  display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px',
                }}
              >
                Choose Photo
              </button>
              <input ref={galleryInputRef} type="file" accept="image/*" style={{ display: 'none' }} onChange={handleFileSelect} />
            </div>

            {selectedFile && (
              <div className={styles.fileInfo}>
                <p>Selected: {selectedFile.name}</p>
                <p>Size: {(selectedFile.size / 1024).toFixed(2)} KB</p>
              </div>
            )}

            <button
              onClick={handleUploadClick}
              className={styles.uploadButton}
              disabled={!selectedFile || parsingInventory}
              style={{ width: '100%', marginTop: '4px' }}
            >
              {parsingInventory ? 'Processing...' : 'Upload & Extract'}
            </button>
          </div>

          {/* OCR flow */}
          {uploadedFilePath && (
            <button onClick={handleOCRClick} className={styles.ocrButton} disabled={runningOCR}>
              {runningOCR ? 'Running OCR...' : 'Run OCR'}
            </button>
          )}

          {uploadStatus && (
            <div className={uploadStatus.includes('success') ? styles.successStatus : styles.errorStatus}>
              <p>{uploadStatus}</p>
            </div>
          )}

          {ocrText && ocrText !== 'Running OCR...' && (
            <div className={styles.ocrResult}>
              <h3>OCR Result:</h3>
              <pre>{ocrText}</pre>
            </div>
          )}

          {ocrText && ocrText !== 'Running OCR...' && (
            <button onClick={handleParseInventory} className={styles.parseButton} disabled={parsingInventory}>
              {parsingInventory ? 'Parsing...' : 'Parse Inventory with AI'}
            </button>
          )}

          {/* Merged item table */}
          {inventory.length > 0 && (
            <div className={styles.inventoryResult}>
              <h3>Items in {currentArea.name} ({inventory.length} total):</h3>
              <p style={{ fontSize: '0.85rem', color: '#666', marginTop: '-8px', marginBottom: '8px' }}>
                Click any cell to edit before exporting
              </p>
              <button onClick={handleExportArea} className={styles.exportButton}>
                Export to Excel
              </button>
              <div className={styles.tableWrapper}>
                <table className={styles.inventoryTable}>
                  <thead>
                    <tr>{getColumns().map((col, idx) => <th key={idx}>{col}</th>)}</tr>
                  </thead>
                  <tbody>
                    {inventory.map((item, index) => (
                      <tr key={index}>
                        {getColumns().map((col, idx) => (
                          <td key={idx}>
                            <input
                              type="text"
                              value={item[col] !== undefined && item[col] !== null ? item[col] : ''}
                              onChange={(e) => {
                                const updated = [...inventory];
                                updated[index][col] = e.target.value;
                                setInventory(updated);
                              }}
                              style={{
                                width: '100%', border: 'none', background: 'transparent',
                                padding: '4px', fontSize: 'inherit', fontFamily: 'inherit',
                                textAlign: typeof item[col] === 'number' ? 'right' : 'left',
                              }}
                            />
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

        </main>
      </div>
    );
  }
}
